// HMAC validation for webhook path
const sig = $input.first().json.headers?.['x-hub-signature-256'];
if (sig) {
  const crypto = require('crypto');
  const body = JSON.stringify($input.first().json.body || {});
  const expected = 'sha256=' + crypto.createHmac('sha256', process.env.N8N_SHARED_SECRET || '').update(body).digest('hex');
  if (sig !== expected) throw new Error('HMAC validation failed — unauthorized webhook call');
}

// Compute week_start (most recent Monday)
const now = new Date();
const day = now.getDay();
const diff = (day === 0 ? -6 : 1 - day);
const monday = new Date(now);
monday.setDate(now.getDate() + diff);
const weekStart = monday.toISOString().split('T')[0];

// If triggered by webhook, extract specific client_id
const webhookBody = $input.first().json.body;
return [{ json: { week_start: weekStart, specific_client_id: webhookBody?.client_id || null } }];

const clients = $input.all().map(i => i.json);
const specificId = $('Validate HMAC + Get Clients').item.json.specific_client_id;
const weekStart = $('Validate HMAC + Get Clients').item.json.week_start;
const filtered = specificId ? clients.filter(c => c.client_id === specificId) : clients;
return filtered.map(c => ({ json: { ...c, week_start: weekStart } }));

const client = $('Split Per Client').item.json;
const config = client.client_config;
const researchRunId = $json[0]?.research_run_id;

// Build niche hashtag from niche string
const nicheHashtag = config.niche.toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 20);
const audienceHashtag = config.target_audience.toLowerCase().replace(/\s+/g, '').substring(0, 20);

return [{
  json: {
    client_id: client.client_id,
    config,
    week_start: client.week_start,
    research_run_id: researchRunId,
    niche_query: config.niche,
    audience_query: config.target_audience,
    niche_hashtag: nicheHashtag,
    audience_hashtag: audienceHashtag,
    api_key: $env.SCRAPECREATORS_API_KEY
  }
}];

// Merge all ScrapeCreators results
const allItems = $input.all();
const seen = new Set();
const videos = [];

for (const item of allItems) {
  const results = item.json?.data || item.json?.videos || item.json?.items || [];
  for (const v of results) {
    const url = v.url || v.share_url || v.video_url;
    if (!url || seen.has(url)) continue;
    seen.add(url);
    const play = parseInt(v.play_count || v.stats?.play_count || 0);
    const like = parseInt(v.digg_count || v.stats?.digg_count || v.like_count || 0);
    const comment = parseInt(v.comment_count || v.stats?.comment_count || 0);
    const share = parseInt(v.share_count || v.stats?.share_count || 0);
    const score = play * 0.5 + like * 0.25 + comment * 0.15 + share * 0.10;
    videos.push({
      tiktok_url: url,
      author_handle: v.author?.uniqueId || v.author_handle || v.username,
      caption: v.desc || v.caption || '',
      stats: { play_count: play, digg_count: like, comment_count: comment, share_count: share },
      score: Math.round(score)
    });
  }
}

videos.sort((a, b) => b.score - a.score);
const top30 = videos.slice(0, 30);
const top10 = top30.slice(0, 10);

const clientData = $('Build Query Pack').item.json;
return [{ json: { client_id: clientData.client_id, config: clientData.config, week_start: clientData.week_start, research_run_id: clientData.research_run_id, top30, top10 } }];

const { top10, top30, client_id, config, week_start, research_run_id } = $input.first().json;
const results = [];

for (let i = 0; i < top10.length; i++) {
  const video = top10[i];
  try {
    // Note: n8n HTTP Request doesn't support synchronous loops well.
    // This code node prepares the payload; actual HTTP calls use a sub-workflow or manual HTTP Request nodes.
    // In production: replace this with n8n's Loop Over Items + HTTP Request node.
    results.push({ ...video, transcript: null, needs_transcript: true });
  } catch(e) {
    results.push({ ...video, transcript: null, needs_transcript: false, transcript_error: e.message });
  }
}

// Merge: top10 (with transcript flag) + videos 11-30 (no transcript)
const allVideos = [
  ...results,
  ...top30.slice(10).map(v => ({ ...v, transcript: null, needs_transcript: false }))
];

return [{ json: { client_id, config, week_start, research_run_id, videos: allVideos } }];

const claudeResponse = $input.first().json;
const analysis = JSON.parse(claudeResponse.content[0].text || '{}');
const prevData = $('Claude Pattern Analysis').item;

// Return array of upsert payloads
const { client_id, research_run_id, week_start, videos } = $('Merge + Score + Deduplicate').item.json;

return videos.map(v => {
  const analysed = (analysis.videos || []).find(a => a.tiktok_url === v.tiktok_url) || {};
  return {
    json: {
      client_id,
      research_run_id,
      source: 'scrapecreators',
      tiktok_url: v.tiktok_url,
      author_handle: v.author_handle,
      caption: v.caption,
      transcript: v.transcript,
      hook_type: analysed.hook_type || null,
      emotional_trigger: analysed.emotional_trigger || null,
      stats: v.stats,
      score: v.score
    }
  };
});
